import 'dart:convert'; import 'dart:io';
String minWindow(String s, String t) { final need = List<int>.filled(128, 0); var missing = t.length; for (final ch in t.codeUnits) need[ch]++; var left = 0, bestStart = 0, bestLen = s.length + 1; for (var right = 0; right < s.length; right++) { final c = s.codeUnitAt(right); if (need[c] > 0) missing--; need[c]--; while (missing == 0) { if (right - left + 1 < bestLen) { bestStart = left; bestLen = right - left + 1; } final lc = s.codeUnitAt(left); need[lc]++; if (need[lc] > 0) missing++; left++; } } return bestLen > s.length ? '' : s.substring(bestStart, bestStart + bestLen); }
Future<void> main() async { final lines = const LineSplitter().convert(await stdin.transform(utf8.decoder).join()); if (lines.isNotEmpty) { final t = int.parse(lines[0]); final out = <String>[]; for (var i = 0; i < t; i++) out.add(minWindow(lines[1 + 2*i], lines[2 + 2*i])); stdout.write(out.join('\n')); } }
